VALUES
  ('islands-d0d1b9a2-moex-00008', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$600,000取得乙公司普通股20%，採權益法會計處理。X1年7月1日， 甲公司再以$300,000購得乙公司10%普通股。乙公司X1年的全年淨利$150,000，係於X1年中 平均實現，且乙公司於X1年5月1日發放現金股利$30,000。試問甲公司於X1年12月31日投 資乙公司的帳面金額為何？', '["$939,000", "$931,500", "$991,500", "$999,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00009', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初成立時，訂定確定福利退休計畫。X1年及X2年當期服務成本分別為$400,000 與$440,000，該公司於X1年及X2年底分別提撥退休金$320,000與$360,000。若計畫資產實際報 酬率為12%，折現率為8%，則下列選項，何者屬於甲公司X2年底有關退休計畫的分錄？', '["借記：退休金費用$433,600", "貸記：現金$37,800", "借記：淨確定福利負債$153,600", "貸記：其他綜合損益—確定福利計畫再衡量數$12,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00010', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '下列何者之會計處理應依照 IAS 41「農業」之規定？①農場為收成水蜜桃而種植之水蜜桃樹', '["漁撈公司漁船出海所捕獲之南極蝦", "僅", "應依IAS41", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00011', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '有關無形資產之會計處理，下列何者正確？', '["非確定耐用年限之無形資產不論是否具有減損跡象都要定期進行減損測試，且減損損失不得迴轉", "於發展階段且達技術可行之無形資產不得攤銷，且不論是否具有減損跡象都要定期進行減損測試", "商譽應取得外部獨立之鑑價報告進行減損測試以符合可驗證性，且減損損失不得迴轉", "研究階段所投入之支出，原則上須立即認列為費用，僅於符合IAS38第57段之所有條件時， 始得認列為無形資產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00012', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '公司發行之下列非累積特別股，何者具有負債組成部分？①可買回（callable）特別股  ②可轉換 固定普通股數（不具重設價格條件）之特別股', '["僅", "具有負債組成部分", "僅", "具有負債組成部分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00013', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '依照國際財務報導準則之觀念架構，下列何者並非屬於「忠實表述」品質特性之構成要素？', '["中立性", "免於錯誤", "可驗證性", "完整性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00014', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年度淨利為$700,000，稅率為20%。全年有普通股200,000股流通在外。若該公司於 X2年初有10%可轉換公司債，面額為$100，流通在外20,000張，每張可換成普通股2股，發行 價格中的負債組成要素相當於面額。此外，該公司X1年初發行賣權6,000個，每個得依$20之 價格賣回1股面額為$10的普通股給公司，普通股全年平均市價為$12。下列何者為用於計算X2年 度稀釋每股盈餘的股數？', '["200,000股", "204,000股", "220,000股", "244,000股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00015', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$2,000,000購入一筆土地，X1年底該土地之公允價值為$3,000,000，X2年9月 進行重估價後，以當時之公允價值$3,800,000售出。若甲公司採重估價模式作後續衡量，且處分 時將累計之重估增值轉入保留盈餘，則X2年底股東權益因為出售土地而增加的淨額為何？', '["$800,000", "$1,000,000", "$1,800,000", "$2,100,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00016', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司因資金短缺，於X1年5月1日將客戶之應收帳款$1,000,000，以有限追索權方式出售給 乙銀行，甲公司保證所移轉之應收帳款至少可收現$700,000。乙銀行負責向客戶收款且不得轉售 該應收帳款，並向甲公司收取應收帳款總額 4%之手續費。甲公司獲得現金$960,000，該保證負 債之公允價值為$3,300。試問對於甲公司而言，於X1年5月1日之相關分錄，下列何者正確？', '["借記：出售金融資產損失$43,300", "借記：手續費用$40,000", "貸記：保證負債$700,000", "貸記：金融資產移轉負債$303,300"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL),
  ('islands-d0d1b9a2-moex-00017', 'islands-d0d1b9a2', 'islands-d0d1b9a2-moex-114-78566e18', 'sub-islands-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$3,000,000買入高污染設備，耐用年限3年，預計3年後無殘值，採直線法 提列折舊。但法令規定3年後須以環保方式處置該設備。若該公司折現率為10%，且估計3年後 須花$100,000處理費，則X1年甲公司應報導與此高污染設備相關的全部費用金額為何？', '["$1,000,000", "$1,025,044", "$1,032,557", "$1,036,667"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "會計"}'::jsonb, NULL)
